// 對應 src/github-pr-notify.ts 的邏輯（inline 版本，n8n Code node 無法 import repo 檔案）
const payload = $input.first().json.body ?? $input.first().json;
const pr = payload.pull_request ?? {};

const titleMatch = typeof pr.title === 'string' ? pr.title.match(/\[([A-Z]+-\d+)\]/) : null;
const jiraKey = titleMatch ? titleMatch[1] : '（無票號）';
const prTitle = typeof pr.title === 'string' ? pr.title : '';
const prUrl = typeof pr.html_url === 'string' ? pr.html_url : '';
const prNumber = typeof pr.number === 'number' || typeof pr.number === 'string' ? pr.number : '';
const branch = pr.head && typeof pr.head.ref === 'string' ? pr.head.ref : '';
const author = pr.user && typeof pr.user.login === 'string' ? pr.user.login : '';

const description = prTitle.replace(/^\[[A-Z]+-\d+\]\s*/, '').trim() || prTitle;
const emailSubject = '[ASUS 審核通知] [' + jiraKey + '] ' + description;

const emailBody = [
  '新 PR 待審核',
  '',
  '票號：' + jiraKey,
  '功能：' + prTitle,
  '分支：' + branch + ' → main',
  'PR 連結：' + prUrl,
  '作者：' + author,
  '',
  '請執行 /addyosmani-review 後至 GitHub 頁面 Approve。',
].join('\n');

return [{
  json: {
    jiraKey, prTitle, prUrl, prNumber, branch, author,
    emailSubject, emailBody,
  }
}];
